const styles = {
  inputContainer: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'flex-end'
  },
  input: { width: { xs: '100px', md: '130px' } },
  inputText: { width: { xs: '180px', md: 'auto' } },
  container: { display: 'flex', flexDirection: 'column', gap: '30px' },
  basicDataContainer: { display: 'flex', flexDirection: 'column', gap: '20px' },
  resultsContainer: { marginBottom: '30px' },
  loadingContainer: {
    display: 'flex',
    justifyContent: 'center'
  }
}

export default styles
